import sys
from itertools import permutations

def solve():
    N = int(sys.stdin.readline())
    R = sys.stdin.readline().strip()
    C = sys.stdin.readline().strip()

    # Each row must contain exactly one A, B, C
    # Each column must contain exactly one A, B, C
    # Leftmost character in row i must be R[i]
    # Topmost character in column j must be C[j]

    # We will try to fill the grid with backtracking
    grid = [['.' for _ in range(N)] for _ in range(N)]
    result = None

    def is_valid(grid):
        # Check rows
        for i in range(N):
            chars = set()
            leftmost = None
            for j in range(N):
                if grid[i][j] != '.':
                    chars.add(grid[i][j])
                    if leftmost is None:
                        leftmost = grid[i][j]
            if len(chars) != 3 or leftmost != R[i]:
                return False

        # Check columns
        for j in range(N):
            chars = set()
            topmost = None
            for i in range(N):
                if grid[i][j] != '.':
                    chars.add(grid[i][j])
                    if topmost is None:
                        topmost = grid[i][j]
            if len(chars) != 3 or topmost != C[j]:
                return False

        return True

    def backtrack(row):
        nonlocal result
        if row == N:
            if is_valid(grid):
                result = ["".join(row) for row in grid]
            return True
        for col in range(N):
            if grid[row][col] == '.':
                for ch in ['A', 'B', 'C']:
                    # Check if character is already in row or column
                    if ch in grid[row] or ch in [grid[i][col] for i in range(N)]:
                        continue
                    grid[row][col] = ch
                    if backtrack(row + 1):
                        return True
                    grid[row][col] = '.'
        return False

    if backtrack(0):
        print("Yes")
        for line in result:
            print(line)
    else:
        print("No")
